function initMap(){
  if(mapInit){leafMap.invalidateSize();return;}
  mapInit=true;
  leafMap=L.map('map',{zoomControl:true,attributionControl:true,scrollWheelZoom:false}).setView([9.2,-66],6);
  L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png',{
    attribution:'&copy; <a href="https://www.openstreetmap.org/copyright">OSM</a> &copy; <a href="https://carto.com/">CARTO</a>',maxZoom:18
  }).addTo(leafMap);

  mapData.forEach(f=>{
    const color=typeColors[f.type]||'#95a5a6';
    const radius=f.bpd>100000?10:f.bpd>50000?8:f.bpd>10000?6:f.cat==='infra'?9:5;
    const m=L.circleMarker([f.lat,f.lon],{radius,fillColor:color,color:'#fff',weight:1,opacity:.8,fillOpacity:.85}).addTo(leafMap);
    m._data=f;
    const prodStr=f.bpd>0?(f.cat==='infra'?`Nameplate: ${f.bpd.toLocaleString()} bpd`:`Production: ${f.bpd.toLocaleString()} bpd`):'Pre-production / Gas';
    const ofacColor=f.ofac.includes('GL-50A')?'#00d26a':f.ofac.includes('EXCLUDED')?'#ff4d4d':f.ofac.includes('disavowed')?'#ff4d4d':'#ff9f1a';
    m.bindPopup(`
      <div style="font-family:'IBM Plex Sans',sans-serif;min-width:220px;">
        <div style="font-size:13px;font-weight:700;margin-bottom:4px;">${f.name}</div>
        <div style="font-size:11px;color:#888;margin-bottom:6px;">${f.op}</div>
        <div style="font-size:11px;margin-bottom:3px;"><strong>Type:</strong> ${f.type.replace(/_/g,' ')}</div>
        <div style="font-size:11px;margin-bottom:3px;"><strong>${prodStr}</strong></div>
        <div style="font-size:11px;margin-bottom:6px;">OFAC: <span style="color:${ofacColor};font-weight:600;">${f.ofac}</span></div>
        <div style="font-size:10px;color:#aaa;line-height:1.4;">${f.notes}</div>
      </div>
    `,{className:'custom-popup',maxWidth:280});
    mapMarkers.push(m);
  });

  // Style popups
  const style=document.createElement('style');
  style.textContent=`.custom-popup .leaflet-popup-content-wrapper{background:#161a22;color:#e8eaed;border:1px solid rgba(255,255,255,.1);border-radius:4px;box-shadow:0 4px 20px rgba(0,0,0,.5);}.custom-popup .leaflet-popup-tip{background:#161a22;border:1px solid rgba(255,255,255,.1);}.custom-popup .leaflet-popup-close-button{color:#5f6368;}.custom-popup .leaflet-popup-close-button:hover{color:#e8eaed;}`;
  document.head.appendChild(style);
}

function mapFilter(f,el){
  document.getElementById('mapFilterTabs').querySelectorAll('.ptab').forEach(t=>t.classList.remove('on'));el.classList.add('on');
  mapMarkers.forEach(m=>{
    const d=m._data;
    let show=true;
    if(f==='field')show=d.cat==='field';

    if(f==='field')show=d.cat==='field';
    else if(f==='gas')show=d.cat==='gas';
    else if(f==='infra')show=d.cat==='infra';
    else if(f==='gl50a')show=gl50aOps.some(op=>d.op.includes(op));
    else if(f==='excluded')show=d.ofac.includes('EXCLUDED')||d.ofac.includes('disavowed');
    m.setStyle({fillOpacity:show?.85:.08,opacity:show?.8:.08});
    if(show)m.setRadius(m._data.bpd>100000?10:m._data.bpd>50000?8:m._data.bpd>10000?6:m._data.cat==='infra'?9:5);
    else m.setRadius(3);
  });
}

// INIT
renderT('tbl','all',false);
const obs=new IntersectionObserver(ents=>{ents.forEach(e=>{if(e.isIntersecting){e.target.querySelectorAll('.inf-fill').forEach(b=>{b.style.width=b.dataset.w+'%';});obs.unobserve(e.target);}});},{threshold:.2});
document.querySelectorAll('.inf').forEach(i=>obs.observe(i));

