try {
  var pr = await fetch('/api/production');
  if(pr.ok) {
    var pd = await pr.json();
    if(pd.data && pd.data.length > 0 && pd.source === 'eia') {
      var latest = pd.data[0];
      var kpi0 = document.querySelectorAll('.kpi')[0];
      if(kpi0) {
        var val = kpi0.querySelector('.kpi-v');
